// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC721/extensions/ERC721URIStorage.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

// ─────────────────────────────────────────────────────────────────────────────
//  AgentIdentityRegistry — ERC-8004 "Trustless Agents" Identity Registry
//
//  ERC-721 where each token = an on-chain AI agent identity. `agentId` is the
//  tokenId and `agentURI` is the tokenURI, which resolves to the agent's
//  registration file (capabilities, endpoints, contracts, trust models).
//  Implements the ERC-8004 core Identity Registry interface:
//    register() / register(uri) / register(uri, metadata[]) → agentId
//    setMetadata / getMetadata
//    events Registered, MetadataSet
//
//  This is the Mantle Sepolia deployment for the Aether copy-trading agent
//  (Mantle Turing Test hackathon, Phase I: ERC-8004 identity on testnet).
//  If the hackathon provides a canonical registry, point to that address instead.
// ─────────────────────────────────────────────────────────────────────────────
contract AgentIdentityRegistry is ERC721URIStorage, ReentrancyGuard {

    struct MetadataEntry {
        string key;
        bytes  value;
    }

    uint256 private _nextId = 1;

    /// @dev agentId => key => value
    mapping(uint256 => mapping(string => bytes)) private _metadata;

    event Registered(uint256 indexed agentId, string tokenURI, address indexed owner);
    event MetadataSet(uint256 indexed agentId, string indexed indexedKey, string key, bytes value);

    constructor() ERC721("ERC-8004 Trustless Agent", "AGENT") {}

    // ── Registration ───────────────────────────────────────────────────────────

    /// @notice Register an agent with an agentURI and an initial metadata set.
    function register(string calldata agentURI, MetadataEntry[] calldata metadata)
        external nonReentrant returns (uint256 agentId)
    {
        agentId = _register(agentURI);
        for (uint256 i = 0; i < metadata.length; i++) {
            _metadata[agentId][metadata[i].key] = metadata[i].value;
            emit MetadataSet(agentId, metadata[i].key, metadata[i].key, metadata[i].value);
        }
    }

    /// @notice Register an agent with just an agentURI.
    function register(string calldata agentURI) external nonReentrant returns (uint256 agentId) {
        agentId = _register(agentURI);
    }

    /// @notice Register an agent with no URI (set it later via standard ERC-721 means).
    function register() external nonReentrant returns (uint256 agentId) {
        agentId = _register("");
    }

    function _register(string memory agentURI) internal returns (uint256 agentId) {
        agentId = _nextId++;
        _safeMint(msg.sender, agentId);
        if (bytes(agentURI).length > 0) {
            _setTokenURI(agentId, agentURI);
        }
        emit Registered(agentId, agentURI, msg.sender);
    }

    // ── Metadata ───────────────────────────────────────────────────────────────

    /// @notice Set a metadata key/value on an agent (owner only).
    function setMetadata(uint256 agentId, string calldata key, bytes calldata value) external {
        require(ownerOf(agentId) == msg.sender, "AIR: not agent owner");
        _metadata[agentId][key] = value;
        emit MetadataSet(agentId, key, key, value);
    }

    /// @notice Read a metadata value for an agent.
    function getMetadata(uint256 agentId, string calldata key) external view returns (bytes memory) {
        return _metadata[agentId][key];
    }

    /// @notice Total number of registered agents.
    function totalAgents() external view returns (uint256) {
        return _nextId - 1;
    }
}

contracts/aUSD.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";

// ─────────────────────────────────────────────────────────────────────────────
//   █████╗ ██╗   ██╗███████╗██████╗
//  ██╔══██╗██║   ██║██╔════╝██╔══██╗
//  ███████║██║   ██║███████╗██║  ██║
//  ██╔══██║██║   ██║╚════██║██║  ██║
//  ██║  ██║╚██████╔╝███████║██████╔╝
//
//  aUSD — Aionis test stablecoin
//  Chain: Mantle Sepolia Testnet (5003)
// ─────────────────────────────────────────────────────────────────────────────

/**
 * @title  aUSD
 * @notice Test stablecoin for the Aionis copy-trading platform.
 *         Pegged 1:1 to USD for accounting purposes.
 *         6 decimals — matches real USDC denomination.
 *
 * @dev    Two mint paths:
 *           1. faucet()  — anyone can claim 10,000 aUSD every 24 hours
 *           2. mint()    — owner or whitelisted minters (e.g. VaultManager)
 */
contract aUSD is ERC20 {

    // ── Constants ─────────────────────────────────────────────────────────────

    uint256 public constant FAUCET_AMOUNT   = 10_000 * 10 ** 6;   // 10,000 aUSD
    uint256 public constant FAUCET_COOLDOWN = 24 hours;

    // ── State ─────────────────────────────────────────────────────────────────

    address public owner;

    /// @notice Addresses whitelisted to call mint() — e.g. VaultManager
    mapping(address => bool) public minters;

    /// @notice Last faucet claim timestamp per address
    mapping(address => uint256) public lastFaucet;

    // ── Events ────────────────────────────────────────────────────────────────

    event FaucetClaimed(address indexed user, uint256 amount);
    event MinterAdded(address indexed minter);
    event MinterRemoved(address indexed minter);
    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);

    // ── Modifiers ─────────────────────────────────────────────────────────────

    modifier onlyOwner() {
        require(msg.sender == owner, "aUSD: not owner");
        _;
    }

    modifier onlyMinter() {
        require(minters[msg.sender] || msg.sender == owner, "aUSD: not minter");
        _;
    }

    // ── Constructor ───────────────────────────────────────────────────────────

    constructor() ERC20("Aionis USD", "aUSD") {
        owner = msg.sender;
    }

    // ── Decimals override ─────────────────────────────────────────────────────

    /// @notice 6 decimals — matches USDC denomination
    function decimals() public pure override returns (uint8) {
        return 6;
    }

    // ── Faucet ────────────────────────────────────────────────────────────────

    /**
     * @notice Claim 10,000 aUSD. Rate-limited to once every 24 hours per address.
     */
    function faucet() external {
        require(
            block.timestamp >= lastFaucet[msg.sender] + FAUCET_COOLDOWN,
            "aUSD: cooldown active"
        );
        lastFaucet[msg.sender] = block.timestamp;
        _mint(msg.sender, FAUCET_AMOUNT);
        emit FaucetClaimed(msg.sender, FAUCET_AMOUNT);
    }

    /**
     * @notice Returns seconds remaining until the next faucet claim is available.
     *         Returns 0 if the address can claim right now.
     */
    function faucetCooldownRemaining(address user) external view returns (uint256) {
        uint256 nextClaim = lastFaucet[user] + FAUCET_COOLDOWN;
        if (block.timestamp >= nextClaim) return 0;
        return nextClaim - block.timestamp;
    }

    // ── Mint ──────────────────────────────────────────────────────────────────

    /**
     * @notice Mint aUSD to any address. Callable by owner or whitelisted minters.
     * @param to     Recipient address
     * @param amount Amount in aUSD base units (6 decimals)
     */
    function mint(address to, uint256 amount) external onlyMinter {
        _mint(to, amount);
    }

    // ── Minter management ─────────────────────────────────────────────────────

    /// @notice Whitelist an address (e.g. VaultManager) to call mint()
    function addMinter(address minter) external onlyOwner {
        minters[minter] = true;
        emit MinterAdded(minter);
    }

    /// @notice Remove minting rights
    function removeMinter(address minter) external onlyOwner {
        minters[minter] = false;
        emit MinterRemoved(minter);
    }

    // ── Ownership ─────────────────────────────────────────────────────────────

    function transferOwnership(address newOwner) external onlyOwner {
        require(newOwner != address(0), "aUSD: zero address");
        emit OwnershipTransferred(owner, newOwner);
        owner = newOwner;
    }
}

contracts/FollowerRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/// @title FollowerRegistry
/// @notice On-chain registry for StellaAlpha paper copy-trading on Mantle Sepolia Testnet.
///         No real funds are held. virtualUsdc is an off-chain accounting unit stored
///         here for transparency only.
contract FollowerRegistry {

    // ── Structs ──────────────────────────────────────────────────────────────

    struct Vault {
        uint256 virtualUsdc;     // 6 decimals — mirrors USDC.e denomination
        uint256 startingCapital;
        bool    exists;
    }

    // ── Storage ──────────────────────────────────────────────────────────────

    mapping(address => Vault)                       public vaults;
    mapping(address => address[])                   public following;   // follower → leaders[]
    mapping(address => address[])                   public followers;   // leader   → followers[]
    mapping(address => mapping(address => bool))    public isFollowing;
    mapping(address => mapping(address => uint256)) public followIndex; // O(1) removal

    // ── Events ───────────────────────────────────────────────────────────────

    event VaultCreated(address indexed user, uint256 virtualUsdc);
    event VaultReset(address indexed user, uint256 virtualUsdc);
    event Followed(address indexed follower, address indexed leader);
    event Unfollowed(address indexed follower, address indexed leader);

    // ── Vault ────────────────────────────────────────────────────────────────

    /// @param virtualUsdc Starting paper capital in USDC.e units (6 decimals).
    ///                    Example: 1000 USDC.e = 1_000_000_000
    function createVault(uint256 virtualUsdc) external {
        require(!vaults[msg.sender].exists, "Vault already exists");
        require(virtualUsdc >= 1e6, "Minimum 1 USDC.e");
        vaults[msg.sender] = Vault({
            virtualUsdc:     virtualUsdc,
            startingCapital: virtualUsdc,
            exists:          true
        });
        emit VaultCreated(msg.sender, virtualUsdc);
    }

    /// @notice Reset vault to new starting capital (also clears all follows).
    function resetVault(uint256 virtualUsdc) external {
        require(vaults[msg.sender].exists, "No vault");
        require(virtualUsdc >= 1e6, "Minimum 1 USDC.e");

        address[] memory leaders = following[msg.sender];
        for (uint256 i = 0; i < leaders.length; i++) {
            _removeFollower(leaders[i], msg.sender);
            isFollowing[msg.sender][leaders[i]] = false;
        }
        delete following[msg.sender];

        vaults[msg.sender].virtualUsdc     = virtualUsdc;
        vaults[msg.sender].startingCapital = virtualUsdc;
        emit VaultReset(msg.sender, virtualUsdc);
    }

    // ── Follow / Unfollow ────────────────────────────────────────────────────

    function follow(address leader) external {
        require(vaults[msg.sender].exists,        "Create vault first");
        require(!isFollowing[msg.sender][leader],  "Already following");
        require(leader != msg.sender,              "Cannot follow yourself");
        require(leader != address(0),              "Invalid leader");

        followIndex[msg.sender][leader] = following[msg.sender].length;
        following[msg.sender].push(leader);
        followers[leader].push(msg.sender);
        isFollowing[msg.sender][leader] = true;

        emit Followed(msg.sender, leader);
    }

    function unfollow(address leader) external {
        require(isFollowing[msg.sender][leader], "Not following");

        isFollowing[msg.sender][leader] = false;

        // O(1) swap-and-pop from following[]
        uint256 idx  = followIndex[msg.sender][leader];
        address[] storage f = following[msg.sender];
        address last = f[f.length - 1];
        f[idx] = last;
        followIndex[msg.sender][last] = idx;
        f.pop();
        delete followIndex[msg.sender][leader];

        _removeFollower(leader, msg.sender);

        emit Unfollowed(msg.sender, leader);
    }

    // ── Views ─────────────────────────────────────────────────────────────────

    function getFollowing(address user) external view returns (address[] memory) {
        return following[user];
    }

    function getFollowers(address leader) external view returns (address[] memory) {
        return followers[leader];
    }

    function getVault(address user)
        external view
        returns (uint256 virtualUsdc, uint256 startingCapital, bool exists)
    {
        Vault storage v = vaults[user];
        return (v.virtualUsdc, v.startingCapital, v.exists);
    }

    // ── Internal ──────────────────────────────────────────────────────────────

    function _removeFollower(address leader, address follower) internal {
        address[] storage fl = followers[leader];
        for (uint256 i = 0; i < fl.length; i++) {
            if (fl[i] == follower) {
                fl[i] = fl[fl.length - 1];
                fl.pop();
                return;
            }
        }
    }
}

